import{_ as t,c as r,o as a,ag as i}from"./chunks/framework.By5zrZ8k.js";const p=JSON.parse('{"title":"RAG Projects","description":"","frontmatter":{},"headers":[],"relativePath":"projects/mlai/rag/README.md","filePath":"projects/mlai/rag/README.md","lastUpdated":1773425138000}'),o={name:"projects/mlai/rag/README.md"};function n(s,e,l,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="rag-projects" tabindex="-1">RAG Projects <a class="header-anchor" href="#rag-projects" aria-label="Permalink to &quot;RAG Projects&quot;">​</a></h1><p>This folder groups together NetApp&#39;s Retrieval-Augmented Generation (RAG) project patterns under a single location:</p><ul><li><code>document-rag</code></li><li><code>graph-rag</code></li><li><code>hybrid-rag-bm25</code></li><li><code>hybrid-rag-graph</code></li></ul><p>These four projects are related, but they are <strong>not interchangeable</strong>. Each one uses a different grounding model and retrieval strategy, which changes how the system behaves in areas like explainability, governance, semantic recall, and operational complexity.</p><h2 id="at-a-glance" tabindex="-1">At a Glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to &quot;At a Glance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Project</th><th>Primary Grounding Model</th><th>Supporting Retrieval</th><th>Best Fit</th><th>Main Tradeoff</th></tr></thead><tbody><tr><td><code>document-rag</code></td><td>Documents + BM25 lexical search</td><td>Optional entity enrichment / vectors as augmentation</td><td>Deterministic document retrieval with strong auditability</td><td>Less semantic flexibility than hybrid approaches</td></tr><tr><td><code>graph-rag</code></td><td>Knowledge graph (nodes + relationships)</td><td>Graph traversals across entities and concepts</td><td>Multi-hop reasoning, lineage, and explainable fact paths</td><td>Higher modeling and operational complexity</td></tr><tr><td><code>hybrid-rag-bm25</code></td><td>BM25 lexical grounding</td><td>Vector search for semantic expansion</td><td>Balanced precision + recall without graph overhead</td><td>More complex than pure document RAG</td></tr><tr><td><code>hybrid-rag-graph</code></td><td>Knowledge graph for truth grounding</td><td>Vector search for contextual detail</td><td>Fact-traceable retrieval with richer semantic context</td><td>Highest implementation and operational complexity</td></tr></tbody></table><h2 id="how-these-projects-differ" tabindex="-1">How These Projects Differ <a class="header-anchor" href="#how-these-projects-differ" aria-label="Permalink to &quot;How These Projects Differ&quot;">​</a></h2><h3 id="_1-document-rag" tabindex="-1">1. <code>document-rag</code> <a class="header-anchor" href="#_1-document-rag" aria-label="Permalink to &quot;1. `document-rag`&quot;">​</a></h3><p><strong>What it is</strong></p><p><code>document-rag</code> is the most document-centric and deterministic option of the four. It treats retrieval as an <strong>auditable search problem</strong>, centered on <strong>BM25 lexical search</strong> over documents and explicit fields, with entity extraction used to enrich the retrieval pipeline. Its emphasis is explainability, reproducibility, and governance-ready behavior. citeturn468422view0</p><p><strong>How it works</strong></p><ul><li>Uses <strong>BM25 lexical search</strong> as the primary retrieval mechanism.</li><li>Grounds answers in retrieved documents and explicit terms rather than semantic similarity alone.</li><li>May use vectors as augmentation, but <strong>not as the authoritative retrieval layer</strong>. citeturn468422view0</li></ul><p><strong>Use this when</strong></p><ul><li>You need highly deterministic retrieval behavior.</li><li>You want to explain exactly <strong>why</strong> a document matched.</li><li>You care about audit trails, compliance, and stable reproducibility.</li><li>You do not need graph traversal or heavy semantic expansion.</li></ul><p><strong>Strengths</strong></p><ul><li>Strong explainability.</li><li>Repeatable results over the same corpus.</li><li>Clear governance boundaries around documents and metadata. citeturn468422view0</li></ul><p><strong>Tradeoff</strong></p><p>Compared with the hybrid variants, <code>document-rag</code> gives up some semantic flexibility in exchange for tighter control and simpler reasoning about retrieval.</p><h3 id="_2-graph-rag" tabindex="-1">2. <code>graph-rag</code> <a class="header-anchor" href="#_2-graph-rag" aria-label="Permalink to &quot;2. `graph-rag`&quot;">​</a></h3><p><strong>What it is</strong></p><p><code>graph-rag</code> is the most explicitly relational option. Instead of grounding answers only in retrieved documents or chunks, it uses a <strong>knowledge graph</strong> made of nodes and relationships. That makes it well suited for scenarios where the system must trace facts across entities, concepts, and linked evidence. citeturn468422view1</p><p><strong>How it works</strong></p><ul><li>Stores knowledge as <strong>entities, nodes, and relationships</strong>.</li><li>Retrieves information through <strong>graph traversals</strong> rather than only keyword or semantic similarity search.</li><li>Focuses on explicit provenance, multi-hop reasoning, and readable query paths. citeturn468422view1</li></ul><p><strong>Use this when</strong></p><ul><li>You need <strong>multi-step reasoning</strong> across related entities.</li><li>You want graph-based provenance and fact lineage.</li><li>You need explainability that shows <strong>how facts connect</strong>, not only which documents matched.</li><li>Your domain has meaningful entity relationships worth modeling explicitly.</li></ul><p><strong>Strengths</strong></p><ul><li>Excellent fact traceability.</li><li>Natural support for multi-hop reasoning.</li><li>Strong governance and lineage through graph structure. citeturn468422view1</li></ul><p><strong>Tradeoff</strong></p><p><code>graph-rag</code> usually requires more data modeling, ontology discipline, and operational care than document-centric retrieval. It pays off when relationships matter; otherwise, it can be more machinery than the problem deserves.</p><h3 id="_3-hybrid-rag-bm25" tabindex="-1">3. <code>hybrid-rag-bm25</code> <a class="header-anchor" href="#_3-hybrid-rag-bm25" aria-label="Permalink to &quot;3. `hybrid-rag-bm25`&quot;">​</a></h3><p><strong>What it is</strong></p><p><code>hybrid-rag-bm25</code> combines <strong>BM25 lexical search</strong> with <strong>vector retrieval</strong>. The architectural idea is clear: let BM25 provide deterministic, explainable grounding, then use vectors to broaden recall for paraphrases, related phrasing, and semantically similar content. The repo positions BM25 as the anchor and vectors as support. citeturn468422view2</p><p><strong>How it works</strong></p><ul><li>Uses <strong>BM25 first</strong> for lexical grounding.</li><li>Uses <strong>vector embeddings</strong> to extend semantic coverage.</li><li>Keeps retrieval explainable because lexical evidence remains visible and auditable. citeturn468422view2</li></ul><p><strong>Use this when</strong></p><ul><li>You want better recall than pure BM25 can provide.</li><li>You still need deterministic grounding and explainability.</li><li>You want many of the governance benefits of advanced RAG without introducing graph infrastructure.</li><li>You need a practical middle ground between classic search and semantic retrieval.</li></ul><p><strong>Strengths</strong></p><ul><li>Strong balance of precision and recall.</li><li>Better semantic coverage than <code>document-rag</code>.</li><li>Lower overhead than graph-based architectures. citeturn468422view2</li></ul><p><strong>Tradeoff</strong></p><p>This project is more operationally complex than pure document RAG, but it remains materially simpler than graph-based systems. Think of it as the “grown-up default” for teams that want semantic range without surrendering control.</p><h3 id="_4-hybrid-rag-graph" tabindex="-1">4. <code>hybrid-rag-graph</code> <a class="header-anchor" href="#_4-hybrid-rag-graph" aria-label="Permalink to &quot;4. `hybrid-rag-graph`&quot;">​</a></h3><p><strong>What it is</strong></p><p><code>hybrid-rag-graph</code> combines <strong>graph-based truth grounding</strong> with <strong>vector-based semantic context</strong>. It extracts entities and relationships from source material into a knowledge graph, while also storing chunk embeddings for narrative detail and semantic expansion. The graph carries the truth model; vectors add supporting context. citeturn468422view3</p><p><strong>How it works</strong></p><ul><li>Builds a <strong>Knowledge Graph</strong> from extracted entities and triplets.</li><li>Uses the graph for explicit truth grounding and provenance.</li><li>Uses <strong>vector search</strong> to retrieve surrounding detail, nuance, and semantically related context. citeturn468422view3</li></ul><p><strong>Use this when</strong></p><ul><li>You need graph-level explainability <strong>and</strong> semantic context retrieval.</li><li>You want fact grounding constrained by explicit relationships.</li><li>You need richer answers than a graph alone might provide.</li><li>Your environment requires strong governance, provenance, and operational controls.</li></ul><p><strong>Strengths</strong></p><ul><li>Strongest blend of fact traceability and contextual completeness.</li><li>Reduced semantic drift compared with vector-first pipelines.</li><li>Best fit for high-governance, high-explainability RAG systems. citeturn468422view3</li></ul><p><strong>Tradeoff</strong></p><p>This is the most sophisticated option in the set. It also comes with the most moving parts: graph modeling, vector infrastructure, memory tiering, operational governance, and promotion workflows. Great when you need it. Overkill when you do not.</p><h2 id="choosing-the-right-project" tabindex="-1">Choosing the Right Project <a class="header-anchor" href="#choosing-the-right-project" aria-label="Permalink to &quot;Choosing the Right Project&quot;">​</a></h2><h3 id="choose-document-rag-if" tabindex="-1">Choose <code>document-rag</code> if: <a class="header-anchor" href="#choose-document-rag-if" aria-label="Permalink to &quot;Choose `document-rag` if:&quot;">​</a></h3><ul><li>You want the most deterministic and document-auditable path.</li><li>You care more about reproducibility and compliance than semantic breadth.</li><li>Your corpus is well-structured enough for lexical retrieval to carry most of the workload.</li></ul><h3 id="choose-graph-rag-if" tabindex="-1">Choose <code>graph-rag</code> if: <a class="header-anchor" href="#choose-graph-rag-if" aria-label="Permalink to &quot;Choose `graph-rag` if:&quot;">​</a></h3><ul><li>Your domain depends on explicit relationships between entities.</li><li>You need multi-hop reasoning and graph-path explainability.</li><li>You want retrieval grounded in connected facts rather than only documents or chunks.</li></ul><h3 id="choose-hybrid-rag-bm25-if" tabindex="-1">Choose <code>hybrid-rag-bm25</code> if: <a class="header-anchor" href="#choose-hybrid-rag-bm25-if" aria-label="Permalink to &quot;Choose `hybrid-rag-bm25` if:&quot;">​</a></h3><ul><li>You want a strong production default for enterprise RAG.</li><li>You need BM25 precision plus vector recall.</li><li>You want governance and explainability without graph database overhead.</li></ul><h3 id="choose-hybrid-rag-graph-if" tabindex="-1">Choose <code>hybrid-rag-graph</code> if: <a class="header-anchor" href="#choose-hybrid-rag-graph-if" aria-label="Permalink to &quot;Choose `hybrid-rag-graph` if:&quot;">​</a></h3><ul><li>You need the strongest explainability and provenance model in this folder.</li><li>Your system must combine explicit truth grounding with semantic context.</li><li>You are building for environments where governance, traceability, and factual lineage are core requirements.</li></ul><h2 id="recommended-mental-model" tabindex="-1">Recommended Mental Model <a class="header-anchor" href="#recommended-mental-model" aria-label="Permalink to &quot;Recommended Mental Model&quot;">​</a></h2><p>A useful way to think about these projects is as a progression:</p><ol><li><strong><code>document-rag</code></strong>: retrieve from documents with deterministic lexical grounding.</li><li><strong><code>graph-rag</code></strong>: retrieve from explicit relationships and connected facts.</li><li><strong><code>hybrid-rag-bm25</code></strong>: keep lexical truth grounding, then add semantic recall.</li><li><strong><code>hybrid-rag-graph</code></strong>: keep graph truth grounding, then add semantic recall.</li></ol><p>That means the real design question is not “Which RAG project is best?”</p><p>It is:</p><ul><li>Do you want grounding centered on <strong>documents</strong> or <strong>relationships</strong>?</li><li>Do you need <strong>semantic expansion</strong> or not?</li><li>How much <strong>governance, explainability, and operational complexity</strong> are you prepared to carry?</li></ul><p>That, as usual, is where architecture stops being marketing and starts being engineering.</p><h2 id="source-projects" tabindex="-1">Source Projects <a class="header-anchor" href="#source-projects" aria-label="Permalink to &quot;Source Projects&quot;">​</a></h2><p>These summaries are based on the current project READMEs in the Innovation Labs repository:</p><ul><li><code>document-rag</code> citeturn468422view0</li><li><code>graph-rag</code> citeturn468422view1</li><li><code>hybrid-rag-bm25</code> citeturn468422view2</li><li><code>hybrid-rag-graph</code> citeturn468422view3</li></ul>',70)])])}const u=t(o,[["render",n]]);export{p as __pageData,u as default};
